-type OllamaPullChunk = {
-  status?: string;
-  total?: number;
-  completed?: number;
-  error?: string;
-};
-
-type OllamaPullFailureKind = "http" | "no-body" | "chunk-error" | "network";
-type OllamaPullResult =
-  | { ok: true }
-  | {
-      ok: false;
-      kind: OllamaPullFailureKind;
-      message: string;
-    };
