+
+export type ReleaseAsset = {
+  name?: string;
+  browser_download_url?: string;
+};
+
+export type NamedAsset = {
+  name: string;
+  browser_download_url: string;
+};
+
+type ReleaseResponse = {
+  tag_name?: string;
+  assets?: ReleaseAsset[];
+};
+
+export type SignalInstallResult = {
